+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+enum ViewportClass {
+    Compact,
+    Regular,
+    Wide,
+}
+
+#[must_use]
+fn viewport_class(area: Rect) -> ViewportClass {
+    if area.width >= 132 && area.height >= 36 {
+        ViewportClass::Wide
+    } else if area.width < 96 || area.height < 28 {
+        ViewportClass::Compact
+    } else {
+        ViewportClass::Regular
+    }
+}
+
